using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Uses constructor injection — the SDK creates a new instance per invocation,
/// resolving HttpClient and ILogger from the DI container automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a resource by its ID from the REST API.")]
    public async Task<string> GetResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("GET /api/resources/{Id}", id);
        var response = await httpClient.GetAsync($"api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("List resources with optional filtering. Returns a JSON array.")]
    public async Task<string> ListResources(
        [Description("Filter by category (optional)")] string? category = null,
        [Description("Maximum number of results to return (1-100, default 20)")] int limit = 20,
        CancellationToken cancellationToken = default)
    {
        var query = $"api/resources?limit={limit}";
        if (!string.IsNullOrEmpty(category))
            query += $"&category={Uri.EscapeDataString(category)}";

        logger.LogInformation("GET /{Query}", query);
        var response = await httpClient.GetAsync(query, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new resource. Returns the created resource as JSON.")]
    public async Task<string> CreateResource(
        [Description("Display name for the new resource")] string name,
        [Description("Category to assign (e.g. 'docs', 'images')")] string category,
        [Description("Optional description of the resource")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        var payload = new { name, category, description };
        var json = JsonSerializer.Serialize(payload, JsonOptions);
        var content = new StringContent(json, Encoding.UTF8, "application/json");

        logger.LogInformation("POST /api/resources");
        var response = await httpClient.PostAsync("api/resources", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

